definitions.raw:
CardObjectIdentity {
    physicalCardId: string
    objectId: string
    zoneChangeVersion: number
}

REST_DON_COST {
    count: 1
}

DON_MINUS_COST {
    count: 2,
    selectableZones: [
        LEADER_AREA,
        CHARACTER_AREA,
        COST_AREA
    ]
}

REST_CARD_COST {
    selector: THIS_CARD
}

TRASH_CARD_COST {
    selector: {
        controller: PLAYER,
        zones: [HAND],
        quantity: EXACTLY(1)
    }
}

DRAW_CARD {
    player: PlayerReference
    count: ValueExpression
}

SEARCH {
    look: LOOK_AT_CARDS
    select: SELECT_CARD
    moveSelected: MOVE_CARD
    processRemainder: MOVE_CARD | REORDER_CARDS
}

SELECT_CARD {
    pool: ResultReference
    selector: Selector
}

REST_CARD {
    selector: Selector
}

SET_CARD_ACTIVE {
    selector: Selector
}

GIVE_DON {
    donSelector: Selector

    target: Selector
}

RETURN_DON_TO_DON_DECK {
    selector: Selector
}

GRANT_KEYWORD {
    selector: Selector
    keyword: KeywordEffect
    duration: Duration
}

REMOVE_KEYWORD {
    selector: Selector
    keyword: KeywordEffect
    duration: Duration
}

ADD_EFFECT {
    selector: Selector
    effect: EffectDefinition
    duration: Duration
}

ALLOW_ACTION {
    selector: Selector
    action: PreventableAction
    duration: Duration
}

PREVENT_ACTION {
    selector: selector

    action: SET_CARD_ACTIVE

    causeFilter: REFRESH_PHASE

    duration: UNTIL_NEXT_REFRESH_PHASE(refreshOwner)
}

DECLARE_ATTACK {
    attacker: Selector
    target: Selector
}

CHANGE_ATTACK_TARGET {
    newTarget: Selector
}

DEAL_DAMAGE {
    source: Selector
    targetPlayer: PlayerReference
    amount: ValueExpression
}

CANCEL_ATTACK {
    battle: CURRENT_BATTLE
}
